SELECT * FROM( SELECT ESNTL_ID as "uniqId", 'USR03' as "userTy", EMPLYR_ID as "userId", USER_NM as "userNm", EMAIL_ADRES as "emailAdres", AREA_NO as "areaNo", HOUSE_MIDDLE_TELNO as "middleTelno", HOUSE_END_TELNO as "endTelno", MBTLNUM as "moblphonNo", GROUP_ID as "groupId", EMPLYR_STTUS_CODE as "sttus", to_char(SBSCRB_DE, 'YYYY MM DD') as "sbscrbDe" FROM LET_TN_EMPLYR_INFO ) A WHERE 1=1
AND "sttus" LIKE #{sbscrbSttus}
AND "userId" LIKE #{searchKeyword}
AND "userNm" LIKE '%' || #{searchKeyword} || '%'
ORDER BY "sbscrbDe" DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(1) AS "totcnt" FROM( SELECT ESNTL_ID as "uniqId", 'USR03' as "userTy", EMPLYR_ID as "userId", USER_NM as "userNm", EMAIL_ADRES as "emailAdres", AREA_NO as "areaNo", HOUSE_MIDDLE_TELNO as "middleTelno", HOUSE_END_TELNO as "endTelno", MBTLNUM as "moblphonNo", GROUP_ID as "groupId", EMPLYR_STTUS_CODE as "sttus", to_char(SBSCRB_DE, 'YYYY MM DD') as "sbscrbDe" FROM LET_TN_EMPLYR_INFO ) A WHERE 1=1
AND "sttus" LIKE #{sbscrbSttus}
AND "userId" LIKE #{searchKeyword}
AND "userNm" LIKE '%' || #{searchKeyword} || '%'

mapper.update:

